import React, { useState } from 'react';
import './BookCard.css';

function StarRating({ rating }) {
  return (
    <div className="stars">
      {[1,2,3,4,5].map(s => (
        <span key={s} className={s <= Math.floor(rating) ? 'star star--filled' : 'star'}>★</span>
      ))}
    </div>
  );
}

export default function BookCard({ title, author, image, rating, votes, delay = 0 }) {
  const [loaded, setLoaded] = useState(false);

  return (
    <div className="book-card fade-up" style={{ animationDelay: `${delay}ms` }}>
      <div className="book-card__img-wrap">
        {!loaded && <div className="book-card__skeleton skeleton" />}
        <img
          src={image}
          alt={title}
          onLoad={() => setLoaded(true)}
          style={{ opacity: loaded ? 1 : 0 }}
        />
        <div className="book-card__overlay">
          <span className="book-card__genre">Popular Pick</span>
        </div>
      </div>

      <div className="book-card__body">
        <p className="book-card__author">{author}</p>
        <h3 className="book-card__title">{title}</h3>

        <div className="book-card__footer">
          <StarRating rating={rating} />
          <span className="book-card__meta">{rating?.toFixed(1)} · {votes?.toLocaleString()} votes</span>
        </div>
      </div>
    </div>
  );
}
